import React, { useState } from 'react';
import Card from '../../components/common/Card';
import Badge from '../../components/common/Badge';
import Spinner from '../../components/common/Spinner';
import salaryService from '../../services/salaryService';
import { useCallback, useEffect } from 'react';
import { formatCurrency, formatDate, monthLabel } from '../../utils/formatters';
import { SALARY_STATUS } from '../../constants';
import './SalaryPage.css';

const SalaryPage = () => {
  const [salaries, setSalaries] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState(null);

  const fetch = useCallback(async () => {
    try {
      setLoading(true);
      const { data } = await salaryService.getMySalaries();
      setSalaries(data.data);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetch(); }, [fetch]);

  return (
    <div className="salary-page">
      <div className="salary-grid">
        {/* List */}
        <Card padding={false}>
          <Card.Header>Istoric salarii</Card.Header>
          {loading ? <div className="p-4"><Spinner /></div> : (
            <div className="salary-list">
              {salaries.length === 0
                ? <p className="table-empty">Nu există înregistrări</p>
                : salaries.map((s) => {
                  const st = SALARY_STATUS[s.status];
                  return (
                    <div
                      key={s.id}
                      className={`salary-list-item ${selected?.id === s.id ? 'selected' : ''}`}
                      onClick={() => setSelected(s)}
                    >
                      <div>
                        <p className="salary-period">{monthLabel(s.month, s.year)}</p>
                        <p className="salary-net">{formatCurrency(s.netSalary)}</p>
                      </div>
                      <Badge color={st?.color}>{st?.label}</Badge>
                    </div>
                  );
                })}
            </div>
          )}
        </Card>

        {/* Detail */}
        <Card>
          {!selected ? (
            <div className="salary-empty-detail">
              <p>💰</p>
              <p>Selectează o lună pentru a vedea detaliile</p>
            </div>
          ) : (
            <div className="salary-detail">
              <h3>{monthLabel(selected.month, selected.year)}</h3>
              <Badge color={SALARY_STATUS[selected.status]?.color}>{SALARY_STATUS[selected.status]?.label}</Badge>
              <div className="salary-breakdown">
                {[
                  { label: 'Salariu de bază', value: formatCurrency(selected.baseSalary) },
                  { label: 'Zile lucrate', value: `${selected.workedDays} zile` },
                  { label: 'Ore lucrate', value: `${selected.workedHours}h` },
                  { label: 'Ore suplimentare', value: `${selected.overtimeHours}h` },
                  { label: 'Plată suplimentară', value: formatCurrency(selected.overtimePay) },
                  { label: 'Sporuri / bonusuri', value: formatCurrency(selected.bonusesTotal) },
                  { label: 'Salariu brut', value: formatCurrency(selected.grossSalary), bold: true },
                  { label: 'CAS (25%)', value: `-${formatCurrency(selected.socialContributions * 0.714)}` },
                  { label: 'CASS (10%)', value: `-${formatCurrency(selected.socialContributions * 0.286)}` },
                  { label: 'Impozit venit (10%)', value: `-${formatCurrency(selected.taxAmount)}` },
                  { label: 'Salariu net', value: formatCurrency(selected.netSalary), bold: true, highlight: true },
                ].map((row) => (
                  <div key={row.label} className={`salary-row ${row.bold ? 'salary-row-bold' : ''} ${row.highlight ? 'salary-row-highlight' : ''}`}>
                    <span>{row.label}</span>
                    <span>{row.value}</span>
                  </div>
                ))}
              </div>
              {selected.paidAt && <p className="salary-paid-date">✓ Plătit pe {formatDate(selected.paidAt)}</p>}
            </div>
          )}
        </Card>
      </div>
    </div>
  );
};

export default SalaryPage;
